def test_manager_update_department_missing_mandatory_field():
    auth_header = <get_manager_bearer_token>
    dept_id = <create_test_department>
    payload = {'budget': 50000}
    resp = <post_request>(
        f'/api/departments/{dept_id}',
        json=payload,
        headers={'Authorization': f'Bearer {auth_header}'}
    )
    assert resp.status_code == 400
    body = resp.json()
    assert body['error_code'] == 'VALIDATION_ERROR'
    assert 'name' in str(body)
    assert any(kw in body.get('message', '').lower()
               for kw in ['required', 'mandatory'])
    audit = <query_audit_log>(resource_id=dept_id)
    assert not any(a['action'] == 'update' and
                   a['timestamp'] > <now() - 10 seconds>
                   for a in audit)

def test_manager_update_department_unauthenticated():
    dept_id = <create_test_department>
    payload = {'name': 'New Name', 'budget': 60000}
    resp = <post_request>(
        f'/api/departments/{dept_id}',
        json=payload
    )
    assert resp.status_code == 401
    assert resp.json()['error_code'] in [
        'UNAUTHORIZED', 'AUTH_REQUIRED'
    ]
    dept_current = <get_department>(dept_id)
    assert dept_current['name'] != 'New Name'

def test_manager_update_department_insufficient_role():
    auth_header = <get_employee_bearer_token>
    dept_id = <create_test_department>
    payload = {'name': 'Hacked', 'budget': 99999}
    resp = <post_request>(
        f'/api/departments/{dept_id}',
        json=payload,
        headers={'Authorization': f'Bearer {auth_header}'}
    )
    assert resp.status_code == 403
    assert 'FORBIDDEN' in resp.json()['error_code']
    dept = <get_department>(dept_id)
    assert dept['name'] != 'Hacked'

def test_manager_update_department_name_exceeds_max_length():
    auth_header = <get_manager_bearer_token>
    dept_id = <create_test_department>
    oversized_name = 'A' * 256
    payload = {'name': oversized_name, 'budget': 40000}
    resp = <post_request>(
        f'/api/departments/{dept_id}',
        json=payload,
        headers={'Authorization': f'Bearer {auth_header}'}
    )
    assert resp.status_code == 400
    body = resp.json()
    assert body['error_code'] == 'VALIDATION_ERROR'
    assert 'name' in str(body)
    assert any(kw in body.get('message', '').lower()
               for kw in ['length', 'max', 'exceed'])
